const { sessionId, userId, company_id, chatInput } = $json;
if (!sessionId) throw new Error('sessionId nao informado');
if (!userId) throw new Error('userId nao informado');
if (!company_id) throw new Error('company_id nao informado');
if (!chatInput || !chatInput.trim()) throw new Error('chatInput nao informado');
return [{ json: { ...$json, chatInput: chatInput.trim() } }];

/*
Substitua este node por Postgres/MySQL real.
Consulta esperada:
select u.id as user_id, u.company_id, c.name as company_name, c.workspace_id, c.dataset_id
from users u
join companies c on c.id = u.company_id
where u.id = $json.userId and c.id = $json.company_id and u.status = 'active';
*/

const companyContext = {
  company_id: $json.company_id,
  company_name: 'Empresa Real',
  workspace_id: '00000000-0000-0000-0000-000000000000',
  dataset_id: '11111111-1111-1111-1111-111111111111',
  language: 'pt-BR',
  timezone: 'America/Sao_Paulo',
  powerbi_identity_mode: 'service_principal'
};

return [{ json: { ...$json, companyContext, accessValidated: true } }];

/*
Substitua por leitura real do catalogo salvo no banco.
Se ainda nao existir catalogo persistido, rode um processo offline usando Scanner API/XMLA para popular esta tabela.
*/

const semanticCatalog = {
  measures: [
    { name: 'Receita Total', description: 'Valor total faturado' },
    { name: 'Margem', description: 'Margem total apurada' },
    { name: 'Quantidade Vendida', description: 'Itens vendidos' }
  ],
  dimensions: [
    { table: 'DimRegiao', column: 'Regiao' },
    { table: 'DimProduto', column: 'Produto' },
    { table: 'DimCalendario', column: 'Data' }
  ],
  synonyms: {
    faturamento: 'Receita Total',
    receita: 'Receita Total',
    regiao: 'DimRegiao[Regiao]',
    produto: 'DimProduto[Produto]'
  },
  business_rules: [
    'Faturamento deve usar a medida Receita Total',
    'Quando o usuario falar ultimo mes use o mes fechado anterior',
    'Quando o usuario falar hoje considere o calendario local da empresa'
  ]
};

return [{ json: { ...$json, semanticCatalog } }];

const raw = $json.choices?.[0]?.message?.content;
if (!raw) throw new Error('LLM nao retornou conteudo');
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (error) {
  throw new Error('LLM retornou JSON invalido: ' + raw);
}
if (!parsed.intent) throw new Error('LLM nao retornou intent');
return [{ json: { ...$input.item.json, interpretedIntent: parsed } }];

return [{
  json: {
    sessionId: $json.sessionId,
    company_id: $json.company_id,
    message: $json.interpretedIntent.clarificationQuestion || 'Preciso de mais detalhes para consultar corretamente os dados.',
    metadata: {
      status: 'clarification_required',
      interpretedIntent: $json.interpretedIntent
    }
  }
}];

const dax = $json.interpretedIntent.dax;
if (!dax || typeof dax !== 'string') throw new Error('Nenhuma DAX retornada pela LLM');
return [{ json: { ...$json, daxQuery: dax } }];

const token = $json.access_token;
if (!token) throw new Error('Nao foi possivel obter access_token da Microsoft');
return [{ json: { ...$input.item.json, powerbiAccessToken: token } }];

const message = $json.choices?.[0]?.message?.content || 'Consulta executada com sucesso.';
return [{
  json: {
    sessionId: $input.item.json.sessionId,
    company_id: $input.item.json.company_id,
    message,
    metadata: {
      status: 'success',
      workspace_id: $input.item.json.companyContext.workspace_id,
      dataset_id: $input.item.json.companyContext.dataset_id,
      daxQuery: $input.item.json.daxQuery,
      interpretedIntent: $input.item.json.interpretedIntent,
      rowCount: $input.item.json.queryResult.rows.length,
      rows: $input.item.json.queryResult.rows
    }
  }
}];
